import { InjectionToken, Signal, WritableSignal } from '@angular/core';

export type SidebarVariant = 'sidebar' | 'inset' | 'floating';
export type SidebarSide = 'left' | 'right';
export type SidebarCollapsible = 'offcanvas' | 'icon' | 'none';

export interface SidebarContext {
  readonly open: Signal<boolean>;
  readonly collapsed: Signal<boolean>;
  readonly isMobile: Signal<boolean>;
  readonly sidebarId: string;
  readonly collapsible: WritableSignal<SidebarCollapsible>;
  toggle(): void;
  setOpen(value: boolean): void;
  toggleCollapsed(): void;
  setCollapsed(value: boolean): void;
}

export const SIDEBAR_CONTEXT = new InjectionToken<SidebarContext>('SidebarContext');

import { cva, type VariantProps } from 'class-variance-authority';

export const sidebarVariants = cva(
  'relative flex flex-col shrink-0 transition-[width] duration-200 ease-in-out overflow-hidden',
  {
    variants: {
      nVariant: {
        sidebar: 'bg-sidebar border-r border-sidebar-border',
        inset: 'bg-sidebar/50',
        floating: 'bg-sidebar border border-sidebar-border rounded-lg shadow-md m-2',
      },
    },
    defaultVariants: {
      nVariant: 'sidebar',
    },
  },
);

export const sidebarMenuButtonVariants = cva(
  [
    'flex w-full items-center gap-2 rounded-md text-sm font-medium',
    'outline-none ring-sidebar-ring transition-colors duration-150',
    'hover:bg-sidebar-accent hover:text-sidebar-accent-foreground',
    'focus-visible:ring-2 focus-visible:ring-offset-1',
    'disabled:pointer-events-none disabled:opacity-50',
    '[&>svg]:size-4 [&>svg]:shrink-0',
  ].join(' '),
  {
    variants: {
      nSize: {
        sm: 'h-7 px-2 py-1 text-xs',
        default: 'h-8 px-2 py-1.5',
        lg: 'h-10 px-3 py-2 text-base',
      },
    },
    defaultVariants: {
      nSize: 'default',
    },
  },
);

export type SidebarVariants = VariantProps<typeof sidebarVariants>;
export type SidebarMenuButtonVariants = VariantProps<typeof sidebarMenuButtonVariants>;

import {
  ChangeDetectionStrategy,
  Component,
  OnDestroy,
  OnInit,
  PLATFORM_ID,
  WritableSignal,
  computed,
  effect,
  forwardRef,
  inject,
  input,
  signal,
} from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import {
  SIDEBAR_CONTEXT,
  type SidebarCollapsible,
  type SidebarContext,
} from './sidebar.context';

let _sidebarIdCounter = 0;

@Component({
  selector: 'n-sidebar-provider',
  standalone: true,
  template: `
    @if (_isMobile() && _open()) {
      <div
        class="fixed inset-0 z-40 bg-black/50 transition-opacity duration-300"
        aria-hidden="true"
        (click)="_setOpen(false)"
      ></div>
    }
    <ng-content />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: 'flex h-svh w-full overflow-hidden relative',
    '(document:keydown)': '_handleKeydown($event)',
  },
  providers: [
    {
      provide: SIDEBAR_CONTEXT,
      useFactory: (cmp: SidebarProviderComponent) => cmp.context,
      deps: [forwardRef(() => SidebarProviderComponent)],
    },
  ],
})
export class SidebarProviderComponent implements OnInit, OnDestroy {
  readonly nDefaultOpen = input<boolean>(true);
  readonly nDefaultCollapsed = input<boolean>(false);
  readonly nStorageKey = input<string>('');
  readonly nKeyboardShortcut = input<string>('b');

  private readonly _platformId = inject(PLATFORM_ID);
  private readonly _isBrowser = isPlatformBrowser(this._platformId);
  private readonly _staticId = `n-sidebar-${++_sidebarIdCounter}`;

  protected readonly _open = signal<boolean>(true);
  private readonly _collapsed = signal<boolean>(false);
  protected readonly _isMobile = signal<boolean>(false);
  private readonly _collapsible: WritableSignal<SidebarCollapsible> = signal('offcanvas');

  private _mediaQuery?: MediaQueryList;
  private _mobileListener?: () => void;

  readonly context: SidebarContext = {
    open: this._open.asReadonly(),
    collapsed: this._collapsed.asReadonly(),
    isMobile: this._isMobile.asReadonly(),
    sidebarId: this._staticId,
    collapsible: this._collapsible,
    toggle: () => this._toggle(),
    setOpen: (v) => this._setOpen(v),
    toggleCollapsed: () => this._collapsed.update((v) => !v),
    setCollapsed: (v) => this._collapsed.set(v),
  };

  constructor() {
    if (this._isBrowser) {
      this._mediaQuery = window.matchMedia('(max-width: 767px)');
      this._isMobile.set(this._mediaQuery.matches);
      this._mobileListener = () => this._isMobile.set(this._mediaQuery!.matches);
      this._mediaQuery.addEventListener('change', this._mobileListener);
    }

    effect(() => {
      const key = this.nStorageKey();
      if (!key || !this._isBrowser) return;
      localStorage.setItem(`${key}-open`, String(this._open()));
      localStorage.setItem(`${key}-collapsed`, String(this._collapsed()));
    });
  }

  ngOnInit(): void {
    const key = this.nStorageKey();
    if (key && this._isBrowser) {
      const storedOpen = localStorage.getItem(`${key}-open`);
      const storedCollapsed = localStorage.getItem(`${key}-collapsed`);
      this._open.set(storedOpen !== null ? storedOpen === 'true' : this.nDefaultOpen());
      this._collapsed.set(storedCollapsed !== null ? storedCollapsed === 'true' : this.nDefaultCollapsed());
    } else {
      this._open.set(this.nDefaultOpen());
      this._collapsed.set(this.nDefaultCollapsed());
    }
  }

  ngOnDestroy(): void {
    if (this._mediaQuery && this._mobileListener) {
      this._mediaQuery.removeEventListener('change', this._mobileListener);
    }
  }

  protected _setOpen(value: boolean): void {
    this._open.set(value);
  }

  private _toggle(): void {
    const col = this._collapsible();
    if (col === 'icon') {
      this._collapsed.update((v) => !v);
    } else if (col === 'offcanvas') {
      this._open.update((v) => !v);
    }
  }

  protected _handleKeydown(event: KeyboardEvent): void {
    const shortcut = this.nKeyboardShortcut();
    if (!shortcut) return;
    if ((event.ctrlKey || event.metaKey) && event.key === shortcut) {
      event.preventDefault();
      this._toggle();
    }
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  computed,
  effect,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { SIDEBAR_CONTEXT } from './sidebar.context';
import { sidebarVariants, type SidebarVariants } from './sidebar.variants';
import { type SidebarCollapsible, type SidebarSide } from './sidebar.context';

@Component({
  selector: 'n-sidebar',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.data-state]': 'ctx.collapsed() ? "collapsed" : "expanded"',
    '[attr.data-side]': 'nSide()',
    '[attr.data-variant]': 'nVariant()',
    'data-slot': 'sidebar',
  },
})
export class SidebarComponent implements OnInit {
  readonly nVariant = input<SidebarVariants['nVariant']>('sidebar');
  readonly nSide = input<SidebarSide>('left');
  readonly nCollapsible = input<SidebarCollapsible>('offcanvas');
  readonly nClass = input<string>('');

  protected readonly ctx = inject(SIDEBAR_CONTEXT);

  constructor() {
    effect(() => {
      this.ctx.collapsible.set(this.nCollapsible());
    });
  }

  ngOnInit(): void {
    this.ctx.collapsible.set(this.nCollapsible());
  }

  protected readonly classes = computed(() => {
    const open = this.ctx.open();
    const collapsed = this.ctx.collapsed();
    const isMobile = this.ctx.isMobile();
    const collapsible = this.nCollapsible();
    const variant = this.nVariant();
    const side = this.nSide();

    if (isMobile) {
      return mergeClasses(
        'fixed inset-y-0 z-50 flex flex-col w-72',
        side === 'left' ? 'left-0' : 'right-0',
        'transition-transform duration-300',
        open ? 'translate-x-0 ease-out' : side === 'left' ? '-translate-x-full ease-in' : 'translate-x-full ease-in',
        sidebarVariants({ nVariant: variant }),
        this.nClass(),
      );
    }

    let widthClass: string;
    if (collapsible === 'none') {
      widthClass = 'w-64';
    } else if (collapsible === 'offcanvas') {
      widthClass = open ? 'w-64' : 'w-0';
    } else {
      widthClass = collapsed ? 'w-12' : 'w-64';
    }

    return mergeClasses(
      'h-svh flex-col',
      widthClass,
      sidebarVariants({ nVariant: variant }),
      this.nClass(),
    );
  });
}

